import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import InicioSesion from "./inicioSesion";

const Header = () => {
  const navigate = useNavigate();
  const [loggedIn, setLoggedIn] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [userInfo, setUserInfo] = useState(null);  // Estado para guardar info del usuario

  useEffect(() => {
    // Al iniciar, leer usuario de localStorage y estado loggedIn
    const storedUser = localStorage.getItem("userInfo");
    const isLoggedIn = localStorage.getItem("loggedIn") === "true";
    if (storedUser && isLoggedIn) {
      setUserInfo(JSON.parse(storedUser));
      setLoggedIn(true);
    } else {
      setUserInfo(null);
      setLoggedIn(false);
    }

    // Listener por si cambia localStorage en otra pestaña
    const handleStorageChange = () => {
      const storedUserNew = localStorage.getItem("userInfo");
      const isLoggedInNew = localStorage.getItem("loggedIn") === "true";
      if (storedUserNew && isLoggedInNew) {
        setUserInfo(JSON.parse(storedUserNew));
        setLoggedIn(true);
      } else {
        setUserInfo(null);
        setLoggedIn(false);
      }
    };

    window.addEventListener("storage", handleStorageChange);
    return () => window.removeEventListener("storage", handleStorageChange);
  }, []);

  const handleLoginClick = () => setShowLogin(true);

  // Recibe directamente el usuario autenticado del modal InicioSesion
  const handleLoginSuccess = (usuario) => {
    localStorage.setItem("loggedIn", "true");
    localStorage.setItem("userInfo", JSON.stringify(usuario));
    setUserInfo(usuario);
    setLoggedIn(true);
    setShowLogin(false);
  };

  const handleCloseLogin = () => setShowLogin(false);

  const handleUserClick = () => setMenuOpen((prev) => !prev);

  const handleLogout = () => {
    localStorage.removeItem("loggedIn");
    localStorage.removeItem("userInfo");
    setUserInfo(null);
    setLoggedIn(false);
    setMenuOpen(false);
    navigate("/");
  };

  // --- Tu código de estilos y JSX no cambia ---

  return (
    <>
      <header style={styles.header}>
        {/* ... mismo contenido ... */}
        <img
          src="/media/header/login.png"
          alt={loggedIn ? "Panel de administrador" : "Iniciar sesión"}
          style={styles.iconImg}
          onClick={loggedIn ? handleUserClick : handleLoginClick}
          draggable={false}
          title={loggedIn ? "Panel de administrador" : "Iniciar sesión"}
        />

        {loggedIn && menuOpen && (
          <div style={styles.dropdown}>
            <div
              style={styles.dropdownItem}
              onClick={() => {
                navigate("/editor-empresas");
                setMenuOpen(false);
              }}
            >
              Admin.Empresas
            </div>
            <div
              style={styles.dropdownItem}
              onClick={() => {
                navigate("/editor-usuarios");
                setMenuOpen(false);
              }}
            >
              Admin.Usuarios
            </div>
            <div
              style={{
                ...styles.dropdownItem,
                color: "red",
                borderBottom: "none",
              }}
              onClick={handleLogout}
            >
              Cerrar Sesión
            </div>
          </div>
        )}
      </header>

      {showLogin && (
        <InicioSesion onLogin={handleLoginSuccess} onClose={handleCloseLogin} />
      )}
    </>
  );
};

export default Header;
